var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CHARLIE_RSEVEN_NULL_NULL","text":{"KOREA":"이봐! 뒤쪽은 어때?","JPN":"おい！　後方はどうだ？","ENG":"Hey! How does it look in the rear?","TWN":"喂！後方情況怎麼樣？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"CHARLIE_RSEVEN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......따라오진 않는 것 같군.","JPN":"……追いかけてくる奴はいないようだ。","ENG":"It doesn't seem like we're being followed.","TWN":"……沒有跟上來的樣子。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아무래도 저 녀석들은 고치를 지키기 위해 소환된 녀석들인 것 같아.","JPN":"どうやら、あいつらは繭を守るために召喚されたみたいだな。","ENG":"I bet they were summoned to guard the cocoon.","TWN":"看來這些傢伙是為了保護繭才被召喚出來的。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그나마 저 고치가 완전히 부화한 상태가 아니라 다행이군.","JPN":"あの繭がまだ完全に孵化していないのが不幸中の幸いだ。","ENG":"It's fortunate that it didn't hatch.","TWN":"萬幸的是那個繭還沒有完全孵化。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그랬다면 어지간한 태스크포스들의 연합공격으로도 견적이 안 나올 테니까 말이야.","JPN":"もし孵化してたら、タスクフォース同士で連合攻撃を仕掛けたところで、\\nまるで歯が立たなかっただろうな。","ENG":"If it did, we wouldn't have been able to deal with it, even with a bunch of other TASKFORCE teams.","TWN":"萬一真變成那樣，就算是數個特遣勢力的聯合攻擊，應該也傷不了它一點皮毛吧。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"이봐, 당신들. 이제 와서 말이지만 정말 꽤 하는걸?","JPN":"あんたたち、今さらだけど、本当になかなかやるじゃない。","ENG":"I must tell you, you guys were pretty impressive.","TWN":"喂，你們。雖然現在才這樣說，但你們還挺厲害的嘛？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"솔직히 나이도 어려 보이고 해서 별 기대는 없었는데......","JPN":"正直、見た目も若そうだし大して期待してなかったのに……","ENG":"I didn't have high hopes for you since you looked so young.","TWN":"說實話，我本來看你們年紀小，對你們沒什麼期待的……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"사과하지.","JPN":"見くびって悪かったわ。","ENG":"Let me apologize.","TWN":"我得對你們道歉。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"괜찮아, 괜찮아. 그럴 수도 있지.","JPN":"いいよいいよ、そんなこともあるさ。","ENG":"It’s fine. No worries. It's totally understandable.","TWN":"沒事，沒事。人之常情嘛。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"원래 실력이란 건 겉모습만으로는 알 수 없는......","JPN":"実力ってのはな、見た目だけじゃあわからな……","ENG":"Someone's level of expertise isn't something that you can tell from their appeara—","TWN":"實力光靠外表是看不出來的……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"JESSICA_RSEVEN_NULL_NULL","text":{"KOREA":"아니, 당신 말고 저 소년이랑 카운터 아가씨들 말이야.","JPN":"いや、あんたじゃなくて、あの少年とカウンターのお嬢ちゃんたちのことね。","ENG":"No, not you. I was talking about that boy and the Counter girls.","TWN":"不，不是你，我是指那個男孩和制裁者小姐們。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JESSICA_RSEVEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......거 쌤통이네.","JPN":"……いい気味だね。","ENG":"That serves you right.","TWN":"……活該。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"크흠! 크흠!","JPN":"……ゴ、ゴホン！！","ENG":"Kahem, Kahem!","TWN":"咳咳！咳咳！"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그보다 여긴 생존자가 아무도 없는 거야?","JPN":"それより、ここには生存者が誰もいないの？","ENG":"By the way, how come there aren't any survivors here?","TWN":"話說，這裡就連一個倖存者都沒有嗎？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아까부터 사람이라곤 한 명도 보이질 않는데......","JPN":"さっきから人影がまったくないんだけど……","ENG":"There's not a single soul to be seen.","TWN":"從剛才開始就沒有看到任何一個人……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......그러고 보니 이상하군.","JPN":"……言われてみればおかしいな。","ENG":"It's actually strange.","TWN":"……這樣說來還真是奇怪。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아무리 침식 재난지역이라고 해도 쉘터나 옥상 같은 곳에 살아남은 사람은 있기 마련인데......","JPN":"いくら侵食災害地域とはいえ、シェルターや屋上とかには生存者がいるはずだが……","ENG":"I've never been in a Corruption Disaster area where there isn't a single survivor hiding in shelters on roofs.","TWN":"就算是在侵蝕災難地區，也會有在避難所或屋頂上活下來的人才對啊。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};